class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        int res = 0;
        for (int i = 0; i < n; i++) {
            int x = row[2 * i];
            if ((x % 2 == 0 && row[2 * i + 1] != x + 1) || (x % 2 == 1 && row[2 * i + 1] != x - 1)) {
                for (int j = 2 * i + 1; j < row.size(); j++) {
                    if ((x % 2 == 0 && row[j] == x + 1) || (x % 2 == 1 && row[j] == x - 1)) {
                        swap(row[2 * i + 1], row[j]);
                        res++;
                        break;
                    }
                }
            }
        }
        return res;
    }
};

